import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.猎人锯肉刀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/工厂猎人/3.猎人锯肉刀.md","filePath":"4.资源分区/1.血统与训练/5.通用类/工厂猎人/3.猎人锯肉刀.md"}'),o={name:"4.资源分区/1.血统与训练/5.通用类/工厂猎人/3.猎人锯肉刀.md"};function d(_,e,p,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"_3-猎人锯肉刀",tabindex:"-1"},[n("3.猎人锯肉刀 "),r("a",{class:"header-anchor",href:"#_3-猎人锯肉刀","aria-label":'Permalink to "3.猎人锯肉刀"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="工厂猎人下属-猎人锯肉刀" tabindex="-1">工厂猎人下属：猎人锯肉刀 <a class="header-anchor" href="#工厂猎人下属-猎人锯肉刀" aria-label="Permalink to &quot;工厂猎人下属：猎人锯肉刀&quot;">​</a></h1><p>猎人锯肉刀（逐升武器）<br> D+500<br> 工厂诡兵器，一般用于猎杀行动<br> 这把样子能变形为善用离心力的开山刀，让其面对比自己体积更大的怪兽也能发挥自己的优势----让怪兽变迟钝，让你变得更敏捷。<br> 只不过这是猎人的技巧还是武器的功劳，便不得而知了。<br> 它那嗜血锯齿就象征着猎杀怪兽。<br> 武器类型：刀<br> 体积：3<br> 武器伤害：6L<br> 伤害类型：挥砍<br> 破防： 2破甲 1破魔<br> 效果：你可以使用一个花招动作将此武器变形，变形后你的武器触及距离提高1米，若你在进行攻击后使用自用动作将此武器变形，则触发变形斩，在下一次使用此武器攻击时获得2点dp加值。</p><p>C+1000<br> 武器类型：刀<br> 体积：3<br> 武器伤害：11L<br> 伤害类型：挥砍<br> 破防：3破甲 3破魔 <br> 效果：现在当你使用变形斩时，你获得【吸血2】</p><p>B+2000<br> 武器类型：刀<br> 体积：3<br> 武器伤害：21L<br> 伤害类型：挥砍<br> 破防：8破甲 8破魔，若该武器的破甲以及破魔属性结算后仍有剩余则转化为攻击上的增强加值，至多各转化5点。<br> 效果：现在你的武器附带【幻灭】，并且当你使用武器以变形斩进行攻击时，你的攻击附带二分之一的肢体妨碍点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
